import { TZDate, TZDateMini } from '@date-fns/tz';
import {
  add,
  addDays,
  addHours,
  intervalToDuration,
  startOfHour,
  sub,
} from 'date-fns';
import { type IntlShape } from 'react-intl';

import {
  _parseTimeExpression,
  parseTimeAsTimeValue,
} from '@dynatrace-sdk/units';
import { getTimezone } from '@dynatrace-sdk/user-preferences';

import { formatTimeframeDuration } from './formatting.js';
import {
  getSmallestCommonUnit,
  getTimeDifferenceInUnit,
} from './timeframe-calculations.js';
import { isBiggerThan, isSmallerThan } from './timeframe-selection.js';
import type { Precision } from '../../../core/time/shared.types.js';
import type { Timeframe, TimeValue } from '../../../core/types/time.js';
import {
  getTimeValue,
  removePrecision,
} from '../../../forms/forms-core/time/timeParser.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../constants/timeframeSelectorMessages.js';

/**
 * Formats and returns the display value for given time values, including relative expressions.
 * @internal
 */
export function formatStepperValues(
  from: TimeValue | null,
  to: TimeValue | null,
  intl: IntlShape,
  direction: 'backward' | 'forward',
  selectedOverCalendar?: boolean,
): string {
  // use start of next day when selected over calendar.
  const adjustedTo =
    selectedOverCalendar && to
      ? getTimeValue(
          startOfHour(
            addHours(new TZDateMini(to.absoluteDate, getTimezone()), 1),
          ).toISOString(),
        ) ?? null
      : to;

  const duration = formatTimeframeDuration(from, adjustedTo, intl);
  const prefix = intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.prefix);
  const suffix = intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.suffix, {
    suffix: direction === 'backward' ? 'back' : 'forward',
  });

  return `${prefix}${duration}${suffix}`.trim();
}

/**
 * Calculates a given date by a difference in milliseconds, either forward or backward.
 */
const adjustDate = (
  date: TZDate,
  difference: number,
  direction: 'forward' | 'backward',
  selectedOverCalendar?: boolean,
): string => {
  if (selectedOverCalendar) {
    const daysDifference = Math.round(-difference / (1000 * 60 * 60 * 24));
    date = addDays(
      date,
      direction === 'backward' ? -daysDifference : daysDifference,
    );
    return date.toISOString();
  }

  date.setTime(
    direction === 'backward'
      ? date.getTime() - Math.abs(difference)
      : date.getTime() + Math.abs(difference),
  );
  return date.toISOString();
};

/**
 * Calculates a new time relative value based on the offset amount and difference.
 */
const convertOffsetToExpression = (
  offsetAmount: number,
  diff: number,
  offsetUnit: string,
): string => {
  const totalOffset = diff + offsetAmount;
  if (totalOffset > 0) {
    return `now()+${totalOffset}${offsetUnit}`;
  } else if (totalOffset < 0) {
    return `now()${totalOffset}${offsetUnit}`;
  } else {
    return 'now()';
  }
};

/**
 * Adjusts the timeframe if it is outside the specified min and max limits.
 */
const clampToMin = (
  min: TimeValue | null,
  max: TimeValue | null,
  from: TimeValue,
  to: TimeValue,
  precision?: Precision,
): Timeframe => {
  const relativeNow = TZDateMini.tz(getTimezone()).getTime();

  if (!min) {
    return { from, to };
  }

  const isFromBelowMin = isSmallerThan(from.absoluteDate, min.absoluteDate);
  const isToBelowMin = isSmallerThan(to.absoluteDate, min.absoluteDate);
  const difference = intervalToDuration({
    start: from.absoluteDate,
    end: to.absoluteDate,
  });

  // from is below the min value, to is above the min value.
  // from is adjusted to the min value, to stays the same.
  if (isFromBelowMin && !isToBelowMin) {
    return {
      from: min,
      to,
    };
  }

  const _timezonedMin = new TZDateMini(min.absoluteDate, getTimezone());
  const adjustedTimeISO = new TZDateMini(
    add(_timezonedMin, difference),
    getTimezone(),
  ).toISOString();
  let timeValueAdjusted = parseTimeAsTimeValue(
    adjustedTimeISO,
    relativeNow,
    precision,
  );

  // If the adjusted time exceeds the max value, adjust it to the max value.
  if (max && isBiggerThan(timeValueAdjusted?.absoluteDate, max.absoluteDate)) {
    timeValueAdjusted = max;
  }

  // from and to are both below the min value.
  // from is adjusted to the min value, to is adjusted to min value plus duration.
  if (isFromBelowMin && isToBelowMin) {
    return {
      from: min,
      to: timeValueAdjusted ?? min,
    };
  }

  // from is above the min value, to is below the min value.
  // from stays the same and to is adjusted to the from value plus duration.
  if (!isFromBelowMin && isToBelowMin) {
    return {
      from,
      to: timeValueAdjusted ?? from,
    };
  }

  return { from, to };
};

/**
 * Adjusts the timeframe if it is outside the specified min and max limits.
 */
const clampToMax = (
  min: TimeValue | null,
  max: TimeValue | null,
  from: TimeValue,
  to: TimeValue,
  precision?: Precision,
): Timeframe => {
  const relativeNow = TZDateMini.tz(getTimezone()).getTime();

  if (!max) {
    return { from, to };
  }

  const isFromAboveMax = isBiggerThan(from.absoluteDate, max.absoluteDate);
  const isToAboveMax = isBiggerThan(to.absoluteDate, max.absoluteDate);
  const difference = intervalToDuration({
    start: from.absoluteDate,
    end: to.absoluteDate,
  });

  // from and to are both above the max value.
  // from is adjusted to the max value, to is adjusted to max value minus duration.
  if (isFromAboveMax && isToAboveMax) {
    const _timezonedMax = new TZDateMini(max.absoluteDate, getTimezone());
    const adjustedFrom = new TZDateMini(
      sub(_timezonedMax, difference),
      getTimezone(),
    ).toISOString();

    // If the adjusted from value is below the min value, use min directly
    // to preserve its original expression value (e.g. 'now()-1d').
    if (min && isSmallerThan(adjustedFrom, min.absoluteDate)) {
      return { from: min, to: max };
    }

    return {
      from: parseTimeAsTimeValue(adjustedFrom, relativeNow, precision) ?? max,
      to: max,
    };
  }

  // to is above the max value, from is within bounds.
  // from stays the same, to is adjusted to the max value.
  // This preserves the stepped-forward from (which equals the original to),
  // satisfying the expectation that forward-stepping gives {orig_to, max}.
  if (!isFromAboveMax && isToAboveMax) {
    return {
      from,
      to: max,
    };
  }

  // from is above the max value.
  // from is adjusted to the max value, to stays the same.
  if (isFromAboveMax && !isToAboveMax) {
    const _timezonedFrom = new TZDateMini(from.absoluteDate, getTimezone());
    let adjustedTo = new TZDateMini(
      sub(_timezonedFrom, difference),
      getTimezone(),
    ).toISOString();

    if (min && isSmallerThan(adjustedTo, min.absoluteDate)) {
      adjustedTo = min.absoluteDate;
    }

    return {
      from,
      to: parseTimeAsTimeValue(adjustedTo, relativeNow, precision) ?? from,
    };
  }

  return { from, to };
};

/**
 * Adjusts the timeframe if it is outside the specified min and max limits.
 */
const clampToBoundaries = (
  min: string | undefined,
  max: string | undefined,
  from: TimeValue,
  to: TimeValue,
  precision?: Precision,
): Timeframe | undefined => {
  const relativeNow = TZDateMini.tz(getTimezone()).getTime();
  const parsedMin = parseTimeAsTimeValue(min, relativeNow, precision);
  const parsedMax = parseTimeAsTimeValue(max, relativeNow, precision);
  let result = { from, to };

  result = clampToMin(parsedMin, parsedMax, result.from, result.to, precision);
  result = clampToMax(parsedMin, parsedMax, result.from, result.to, precision);

  return result;
};

/**
 * Adjusts the absolute timeframe based on the specified direction and handles min/max constraints.
 */
const handleAbsolute = (
  originalValue: Timeframe,
  min: string | undefined,
  max: string | undefined,
  direction: 'backward' | 'forward',
  selectedOverCalendar?: boolean,
  precision?: Precision,
): Timeframe => {
  const timezone = getTimezone();
  const from = new TZDateMini(originalValue.from.absoluteDate, timezone);
  const to = new TZDateMini(originalValue.to.absoluteDate, timezone);

  const difference = from.getTime() - to.getTime();

  const adjustedFrom = removePrecision(
    adjustDate(from, difference, direction, selectedOverCalendar),
    precision,
  );
  const adjustedTo = removePrecision(
    adjustDate(to, difference, direction, selectedOverCalendar),
    precision,
  );

  const newTimeframe: Timeframe = {
    from: {
      type: 'iso8601',
      absoluteDate: adjustedFrom,
      value: adjustedFrom,
    },
    to: {
      type: 'iso8601',
      absoluteDate: adjustedTo,
      value: adjustedTo,
    },
  };

  return (
    clampToBoundaries(
      min,
      max,
      newTimeframe.from,
      newTimeframe.to,
      precision,
    ) ?? originalValue
  );
};

/**
 * Adjusts the relative timeframe based on the direction.
 */
const handleExpression = (
  value: Timeframe,
  min: string | undefined,
  max: string | undefined,
  direction: 'forward' | 'backward',
  precision?: Precision,
): Timeframe | undefined => {
  const relativeNow = TZDateMini.tz(getTimezone()).getTime();
  const fromDetails = _parseTimeExpression(value.from.value);
  const toDetails = _parseTimeExpression(value.to.value);
  const offsetUnit = getSmallestCommonUnit(value.from, value.to);
  const fromOffset =
    offsetUnit === fromDetails?.offsetUnit
      ? fromDetails.offsetAmount
      : getTimeDifferenceInUnit(fromDetails, relativeNow, offsetUnit);
  const toOffset =
    offsetUnit === toDetails?.offsetUnit
      ? toDetails.offsetAmount
      : getTimeDifferenceInUnit(toDetails, relativeNow, offsetUnit);

  if (fromOffset === undefined || toOffset === undefined) {
    return undefined;
  }

  const difference = Math.abs(fromOffset - toOffset);
  const newFromValue = convertOffsetToExpression(
    fromOffset,
    difference * -1,
    offsetUnit,
  );
  const newToValue = convertOffsetToExpression(
    toOffset,
    difference,
    offsetUnit,
  );

  const backwardFromParsedTime = parseTimeAsTimeValue(
    newFromValue,
    relativeNow,
    precision,
  );
  const forwardToParsedTime = parseTimeAsTimeValue(
    newToValue,
    relativeNow,
    precision,
  );

  if (!backwardFromParsedTime || !forwardToParsedTime) {
    return undefined;
  }

  const currentBackwardFromParsedTime = parseTimeAsTimeValue(
    convertOffsetToExpression(0, fromOffset, offsetUnit),
    relativeNow,
    precision,
  );
  const currentForwardToParsedTime = parseTimeAsTimeValue(
    convertOffsetToExpression(0, toOffset, offsetUnit),
    relativeNow,
    precision,
  );

  if (!currentBackwardFromParsedTime || !currentForwardToParsedTime) {
    return undefined;
  }

  const newTimeframe: Timeframe =
    direction === 'backward'
      ? {
          from: backwardFromParsedTime,
          to: currentBackwardFromParsedTime,
        }
      : {
          from: currentForwardToParsedTime,
          to: forwardToParsedTime,
        };

  return (
    clampToBoundaries(
      min,
      max,
      newTimeframe.from,
      newTimeframe.to,
      precision,
    ) ?? value
  );
};

/**
 * Adjusts the roundDownExpression timeframe based on the direction.
 */
function handleRoundedTimeframe(
  value: Timeframe,
  min: string | undefined,
  max: string | undefined,
  direction: 'forward' | 'backward',
  precision?: Precision,
): Timeframe | undefined {
  const relativeNow = TZDateMini.tz(getTimezone()).getTime();
  const fromDetails = _parseTimeExpression(value.from.value);
  const toDetails = _parseTimeExpression(value.to.value);
  const offsetUnit = getSmallestCommonUnit(value.from, value.to);

  const fromOffset =
    // same offsetUnit or now() or now()@d.
    offsetUnit === fromDetails?.offsetUnit || fromDetails?.offsetAmount === 0
      ? fromDetails.offsetAmount
      : getTimeDifferenceInUnit(fromDetails, relativeNow, offsetUnit);
  const toOffset =
    // same offsetUnit or now() or now()@d.
    offsetUnit === toDetails?.offsetUnit || toDetails?.offsetAmount === 0
      ? toDetails.offsetAmount
      : getTimeDifferenceInUnit(toDetails, relativeNow, offsetUnit);

  let backwardFromValue = '';
  let forwardToValue = '';

  if (!fromDetails || !toDetails) {
    return undefined;
  }

  const roundDownUnit = fromDetails.roundDownUnit || toDetails.roundDownUnit;

  // If both fromOffset and toOffset are 0 (e.g., @d -> Now).
  if (fromOffset === 0 && toOffset === 0) {
    backwardFromValue = `-1${offsetUnit}@${roundDownUnit}`;
    forwardToValue = `+1${offsetUnit}@${roundDownUnit}`;
  } else {
    const offsetDifference = Math.abs(fromOffset - toOffset);

    backwardFromValue =
      value.from.value === 'now()' && offsetDifference === 1
        ? // Shift backward from now to the rounded down unit (e.g., @d).
          `@${roundDownUnit}`
        : // Otherwise, if 'from' and 'to' are roundDownExpressions (e.g., -40d@M -> -20d@M).
          convertOffsetToExpression(
            offsetDifference * -1,
            fromOffset,
            offsetUnit,
          ) + `@${roundDownUnit}`;
    forwardToValue =
      convertOffsetToExpression(offsetDifference, toOffset, offsetUnit) +
      `@${roundDownUnit}`;
  }

  const backwardFromParsedTime = parseTimeAsTimeValue(
    backwardFromValue,
    relativeNow,
    precision,
  );
  const forwardToParsedTime = parseTimeAsTimeValue(
    forwardToValue,
    relativeNow,
    precision,
  );

  if (!backwardFromParsedTime || !forwardToParsedTime) {
    return undefined;
  }

  const backwardFromCandidate =
    // if the other unit is smaller than this unit convert it to that unit
    fromDetails?.offsetUnit && offsetUnit !== fromDetails?.offsetUnit
      ? // Convert the offset to the smaller unit
        convertOffsetToExpression(0, fromOffset, offsetUnit) +
        `@${roundDownUnit}`
      : value.from.value;

  const forwardToCandidate =
    // if the other unit is smaller than this unit convert it to that unit
    toDetails?.offsetUnit && offsetUnit !== toDetails?.offsetUnit
      ? // Convert the offset to the smaller unit
        convertOffsetToExpression(0, toOffset, offsetUnit) + `@${roundDownUnit}`
      : value.to.value;

  const currentBackwardFromParsedTime = parseTimeAsTimeValue(
    backwardFromCandidate,
    relativeNow,
    precision,
  );

  const currentForwardToParsedTime = parseTimeAsTimeValue(
    forwardToCandidate,
    relativeNow,
    precision,
  );

  if (!currentBackwardFromParsedTime || !currentForwardToParsedTime) {
    return undefined;
  }

  const newTimeframe =
    direction === 'backward'
      ? {
          from: backwardFromParsedTime,
          to: currentBackwardFromParsedTime,
        }
      : {
          from: currentForwardToParsedTime,
          to: forwardToParsedTime,
        };

  return (
    clampToBoundaries(
      min,
      max,
      newTimeframe.from,
      newTimeframe.to,
      precision,
    ) ?? value
  );
}

/**
 * Adjusts the timeframe based on the direction ('backward' or 'forward').
 * Handles different types of timeframes: ISO8601, expressions, and rounded timeframes.
 * @internal
 */
export function getTimeShift(
  value: Timeframe | null,
  config: {
    direction: 'backward' | 'forward';
    min?: string;
    max?: string;
    selectedOverCalendar?: boolean;
    precision?: Precision;
  },
): Timeframe | undefined {
  const { direction, min, max, selectedOverCalendar, precision } = config;

  const isISO8601 = (type: string) => type === 'iso8601';
  const isExpression = (type: string) => type === 'expression';

  if (!value?.from || !value?.to) {
    return undefined;
  }

  if (isISO8601(value.from.type) || isISO8601(value.to.type)) {
    return handleAbsolute(
      value,
      min,
      max,
      direction,
      selectedOverCalendar,
      precision,
    );
  }

  if (isExpression(value.from.type) && isExpression(value.to.type)) {
    const newFrom = _parseTimeExpression(value.from.value);
    const newTo = _parseTimeExpression(value.to.value);

    // no roundedTimeFrame -> handleExpression.
    if (!(newFrom?.roundDownUnit || newTo?.roundDownUnit)) {
      return handleExpression(value, min, max, direction, precision);
    }

    // both are a roundedTimeframe -> handleRoundedTimeframe.
    if (
      // can be a roundedTimeframe or now().
      (newFrom?.roundDownUnit || newFrom?.offsetAmount === 0) &&
      (newTo?.roundDownUnit || newTo?.offsetAmount === 0) &&
      // checks if from and to have different roundDownUnits.
      !(
        newFrom?.roundDownUnit &&
        newTo?.roundDownUnit &&
        newFrom?.roundDownUnit !== newTo?.roundDownUnit
      )
    ) {
      return handleRoundedTimeframe(value, min, max, direction, precision);
    }

    // one is a roundedTimeframe, one is expression -> handleAbsolute.
    return handleAbsolute(value, min, max, direction, false, precision);
  }
  return undefined;
}
